// Consolida dados do dia e do lancamento

const hojeRes = $('Gasto/Leads Hoje').first().json.data || [];
const lancRes = $('Acumulado Lançamento').first().json.data || [];

const hoje = hojeRes[0] || {};
const lancamento = lancRes[0] || {};

function getLeads(d) {
  const a = (d.actions || []).find(x => 
    x.action_type === 'offsite_complete_registration_add_meta_leads' ||
    x.action_type === 'complete_registration'
  );
  return a ? parseInt(a.value) : 0;
}

const gastoHoje = parseFloat(hoje.spend || 0);
const leadsHoje = getLeads(hoje);
const cplHoje = leadsHoje > 0 ? gastoHoje / leadsHoje : null;

const gastoTotal = parseFloat(lancamento.spend || 0);
const leadsTotal = getLeads(lancamento);
const cplTotal = leadsTotal > 0 ? gastoTotal / leadsTotal : null;

// Metas e datas
const META_LEADS = {{META_LEADS}};
const CPL_TARGET = 14;
const CPL_VIAVEL = 16.17;
const INICIO = new Date('{{DATA_INICIO}}');
const FIM = new Date('{{DATA_FIM}}');
const agora = new Date();

const diasTotais = Math.ceil((FIM - INICIO) / (1000*60*60*24));
const diasPassados = Math.ceil((agora - INICIO) / (1000*60*60*24));
const diasRestantes = Math.max(0, Math.ceil((FIM - agora) / (1000*60*60*24)));

const metaPorDia = META_LEADS / diasTotais;
const leadsFaltam = META_LEADS - leadsTotal;
const leadsNecessariosPorDia = diasRestantes > 0 ? leadsFaltam / diasRestantes : 0;

// Projecao do dia: se gastou X ate agora, qual seria o total ate 00h?
// Assumindo que hora atual e ~16h, ja passou 16/24 do dia
const horaAtual = agora.getHours() + agora.getMinutes()/60;
const fracaoDiaPassada = Math.min(1, horaAtual / 24);
const projecaoLeadsHoje = fracaoDiaPassada > 0 ? Math.round(leadsHoje / fracaoDiaPassada) : leadsHoje;
const projecaoGastoHoje = fracaoDiaPassada > 0 ? gastoHoje / fracaoDiaPassada : gastoHoje;

return [{
  json: {
    hoje: {
      gasto: gastoHoje,
      leads: leadsHoje,
      cpl: cplHoje,
      projecao_leads: projecaoLeadsHoje,
      projecao_gasto: projecaoGastoHoje
    },
    lancamento: {
      gasto_total: gastoTotal,
      leads_total: leadsTotal,
      cpl_medio: cplTotal,
      meta_leads: META_LEADS,
      leads_faltam: leadsFaltam,
      percentual_meta: (leadsTotal / META_LEADS * 100)
    },
    calendario: {
      dias_totais: diasTotais,
      dias_passados: diasPassados,
      dias_restantes: diasRestantes,
      meta_por_dia: metaPorDia,
      leads_necessarios_por_dia: leadsNecessariosPorDia
    },
    targets: {
      cpl_individual: CPL_TARGET,
      cpl_viavel_campanha: CPL_VIAVEL
    }
  }
}];
